## Step 2: Create `apps/v4/registry/new-york-v4/examples/stepper-demo.tsx`

Create this file with the following complete content:

```tsx
"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperDescription,
  StepperIndicator,
  StepperItem,
  StepperPanel,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    step: 1,
    title: "Your details",
    description: "Name and email address",
    content:
      "Provide your full name and a valid email address so we can create your account and send you a confirmation.",
  },
  {
    step: 2,
    title: "Choose a plan",
    description: "Free, Pro, or Enterprise",
    content:
      "Select the plan that best fits your needs. You can always upgrade or downgrade later from your account settings.",
  },
  {
    step: 3,
    title: "Confirm order",
    description: "Review and complete",
    content:
      "Review your selections and complete your purchase. A receipt will be sent to your email address.",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="flex w-full max-w-xl flex-col gap-8">
      {/* Horizontal stepper */}
      <Stepper
        activeStep={activeStep}
        onStepChange={setActiveStep}
        orientation="horizontal"
        totalSteps={steps.length}
        className="w-full gap-0"
      >
        {steps.map(({ step, title, description, content }) => (
          <StepperItem key={step} step={step} className="flex-1">
            <StepperTrigger className="w-full gap-3 px-0 py-2">
              <StepperIndicator />
              <div className="flex flex-col items-start gap-0.5 text-left">
                <StepperTitle>{title}</StepperTitle>
                <StepperDescription>{description}</StepperDescription>
              </div>
            </StepperTrigger>
            {step < steps.length && <StepperSeparator />}
            <StepperPanel>
              <p className="text-sm text-muted-foreground">{content}</p>
            </StepperPanel>
          </StepperItem>
        ))}
      </Stepper>

      {/* Navigation buttons */}
      <div className="flex justify-between gap-2">
        <Button
          variant="outline"
          onClick={() => setActiveStep((s) => Math.max(1, s - 1))}
          disabled={activeStep === 1}
        >
          Previous
        </Button>
        <Button
          onClick={() => setActiveStep((s) => Math.min(steps.length, s + 1))}
          disabled={activeStep === steps.length}
        >
          {activeStep === steps.length ? "Finish" : "Next"}
        </Button>
      </div>
    </div>
  )
}
