// ─── Context Types ────────────────────────────────────────────────────────────

type StepperContextProps = {
  activeStep: number
  orientation: "horizontal" | "vertical"
  onStepChange: (step: number) => void
  totalSteps: number
}

type StepperItemContextProps = {
  step: number
  isActive: boolean
  isCompleted: boolean
}

// ─── Contexts ─────────────────────────────────────────────────────────────────

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) throw new Error("useStepper must be used within a <Stepper />")
  return context
}

const StepperItemContext = React.createContext<StepperItemContextProps | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context)
    throw new Error("useStepperItem must be used within a <StepperItem />")
  return context
}

// ─── Stepper (Root) ───────────────────────────────────────────────────────────

type StepperProps = {
  activeStep: number
  onStepChange: (step: number) => void
  orientation?: "horizontal" | "vertical"
  totalSteps: number
}

function Stepper({
  activeStep,
  onStepChange,
  orientation = "horizontal",
  totalSteps,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperProps) {
  return (
    <StepperContext.Provider
      value={{ activeStep, onStepChange, orientation, totalSteps }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex",
          "data-[orientation=horizontal]:flex-row data-[orientation=horizontal]:items-start",
          "data-[orientation=vertical]:flex-col data-[orientation=vertical]:items-stretch",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperItem ──────────────────────────────────────────────────────────────

type StepperItemProps = {
  step: number
}

function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperItemProps) {
  const { activeStep } = useStepper()
  const isActive = activeStep === step
  const isCompleted = activeStep > step

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted }}>
      <div
        data-slot="stepper-item"
        data-active={isActive ? true : undefined}
        data-completed={isCompleted ? true : undefined}
        className={cn(
          "group/stepper-item flex",
          "group-data-[orientation=horizontal]/stepper:flex-col group-data-[orientation=horizontal]/stepper:items-center",
          "group-data-[orientation=vertical]/stepper:flex-row group-data-[orientation=vertical]/stepper:items-start",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ───────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onStepChange } = useStepper()
  const { step } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      onClick={() => onStepChange(step)}
      className={cn(
        "flex items-center gap-2 rounded-md focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50",
        "group-data-[orientation=horizontal]/stepper-item:flex-col group-data-[orientation=horizontal]/stepper-item:items-center",
        "group-data-[orientation=vertical]/stepper-item:flex-row group-data-[orientation=vertical]/stepper-item:items-center",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ─── StepperIndicator ─────────────────────────────────────────────────────────

function StepperIndicator({
  className,
  ...props
}: React.ComponentProps<"span">) {
  const { step, isActive, isCompleted } = useStepperItem()

  return (
    <span
      data-slot="stepper-indicator"
      data-active={isActive ? true : undefined}
      data-completed={isCompleted ? true : undefined}
      className={cn(
        "flex size-8 shrink-0 items-center justify-center rounded-full text-sm font-medium transition-colors",
        "data-[completed]:bg-primary data-[completed]:text-primary-foreground",
        "data-[active]:bg-primary data-[active]:text-primary-foreground data-[active]:ring-2 data-[active]:ring-primary data-[active]:ring-offset-2",
        !isActive &&
          !isCompleted &&
          "border border-border bg-muted text-muted-foreground",
        className
      )}
      {...props}
    >
      {isCompleted ? (
        <Check className="size-4" />
      ) : (
        <span>{step}</span>
      )}
    </span>
  )
}

// ─── StepperTitle ─────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-semibold leading-none", className)}
      {...props}
    />
  )
}

// ─── StepperDescription ───────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ─────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { isCompleted } = useStepperItem()

  return (
    <div
      data-slot="stepper-separator"
