function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ─── Stepper ───────────────────────────────────────────────────────────────────

type StepperProps = {
  activeStep: number
  onStepChange?: (step: number) => void
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  activeStep,
  onStepChange = () => {},
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperProps) {
  return (
    <StepperContext.Provider value={{ activeStep, onStepChange, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
