# Plan: Stepper Compound Component for shadcn/ui

## Context

The shadcn/ui library needs a `Stepper` compound component to support multi-step wizard and onboarding flows. No such component exists today. This plan adds it in a style that is fully consistent with the codebase conventions — using React context for state sharing (as seen in `carousel.tsx`), data-attribute-driven orientation styling (as seen in `tabs.tsx`), and the same registry registration pattern used by every other component.

**Constraint:** Do NOT modify any existing component files. Only create new files and append new entries to the two registry files.

---

## Files to Create (new)

1. `apps/v4/registry/new-york-v4/ui/stepper.tsx` — the component
2. `apps/v4/registry/new-york-v4/examples/stepper-demo.tsx` — the demo

## Files to Modify (append registry entries only)

1. `apps/v4/registry/new-york-v4/ui/_registry.ts` — add entry between `separator` (line 447) and `sheet` (line 448)
2. `apps/v4/registry/new-york-v4/examples/_registry.ts` — add entry between `separator-demo` (line 1937) and `sheet-demo` (line 1938)

---

## Architecture

### Context design (mirrors `carousel.tsx`)

Two React contexts:

- **`StepperContext`** — root-level state: `activeStep`, `onStepChange`, `orientation`
- **`StepperItemContext`** — per-item derived state: `step`, `isActive`, `isCompleted`

Two internal hooks:
- `useStepper()` — throws if used outside `<Stepper />`
- `useStepperItem()` — throws if used outside `<StepperItem />`

### Orientation via data attributes (mirrors `tabs.tsx`)

`orientation` is set once on the root via `data-orientation={orientation}`. All child orientation-aware styling uses `group-data-[orientation=horizontal]/stepper:` and `group-data-[orientation=vertical]/stepper:` selectors. No conditional `className` logic for orientation.

### Separator placement

`StepperSeparator` is placed **between** `StepperItem`s at the `Stepper` root level (not inside `StepperItem`). It takes a `step` prop and reads `activeStep` from `StepperContext` to compute `isCompleted = activeStep > step`. This gives a clean separation of concerns and makes the horizontal connector line work naturally in flex-row.

### Panel visibility

`StepperPanel` lives **inside** `StepperItem`. It reads `isActive` from `StepperItemContext`. When inactive: `hidden` CSS class is applied (`display: none`). When active: no `hidden` class, element is visible.

---

## Sub-components

| Component | Element | data-slot | Notes |
|---|---|---|---|
| `Stepper` | `div` | `stepper` | Root. Provides `StepperContext`. `data-orientation`. `group/stepper`. |
| `StepperItem` | `div` | `stepper-item` | Provides `StepperItemContext`. `data-active`, `data-completed`. `group/stepper-item`. |
| `StepperTrigger` | `button` | `stepper-trigger` | Calls `onStepChange(step)`. Horizontal: `flex-col items-center`. |
| `StepperIndicator` | `span` | `stepper-indicator` | Circle. Shows step number or `CheckIcon`. Active/completed/default states via `data-active`/`data-completed`. |
| `StepperTitle` | `p` | `stepper-title` | `text-sm font-semibold` |
| `StepperDescription` | `p` | `stepper-description` | `text-xs text-muted-foreground` |
| `StepperSeparator` | `div` | `stepper-separator` | Takes `step` prop. Reads `StepperContext`. Horizontal: `h-0.5 flex-1 mt-4`. Vertical: `h-4 w-0.5 ml-[15px]`. |
| `StepperPanel` | `div` | `stepper-panel` | Inside `StepperItem`. Hidden when `!isActive`. Vertical indent: `ml-11`. |

---

## Step 1: Create `apps/v4/registry/new-york-v4/ui/stepper.tsx`

```tsx
"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ─── Context types ─────────────────────────────────────────────────────────────

type StepperContextProps = {
  activeStep: number
  onStepChange: (step: number) => void
  orientation: "horizontal" | "vertical"
}

type StepperItemContextProps = {
  step: number
  isActive: boolean
  isCompleted: boolean
}

// ─── Contexts ──────────────────────────────────────────────────────────────────

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

const StepperItemContext =
  React.createContext<StepperItemContextProps | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ─── Stepper ───────────────────────────────────────────────────────────────────

type StepperProps = {
  activeStep: number
  onStepChange?: (step: number) => void
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  activeStep,
  onStepChange = () => {},
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperProps) {
  return (
    <StepperContext.Provider value={{ activeStep, onStepChange, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex",
          "data-[orientation=horizontal]:flex-row data-[orientation=horizontal]:items-start",
          "data-[orientation=vertical]:flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperItem ───────────────────────────────────────────────────────────────

type StepperItemProps = {
  step: number
}

function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperItemProps) {
  const { activeStep } = useStepper()
  const isActive = activeStep === step
  const isCompleted = activeStep > step

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted }}>
      <div
        data-slot="stepper-item"
        data-active={isActive ? true : undefined}
        data-completed={isCompleted ? true : undefined}
        className={cn(
          "group/stepper-item flex flex-col",
          "group-data-[orientation=horizontal]/stepper:items-center",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ────────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onStepChange } = useStepper()
  const { step } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      onClick={() => onStepChange(step)}
      className={cn(
        "inline-flex items-center gap-2 rounded-md focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50",
        "group-data-[orientation=horizontal]/stepper:flex-col group-data-[orientation=horizontal]/stepper:items-center",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ─── StepperIndicator ──────────────────────────────────────────────────────────

function StepperIndicator({
  className,
  ...props
}: React.ComponentProps<"span">) {
  const { step, isActive, isCompleted } = useStepperItem()

  return (
    <span
      data-slot="stepper-indicator"
      data-active={isActive ? true : undefined}
      data-completed={isCompleted ? true : undefined}
      className={cn(
        "flex size-8 shrink-0 items-center justify-center rounded-full border text-sm font-medium transition-colors",
        "data-[completed]:border-primary data-[completed]:bg-primary data-[completed]:text-primary-foreground",
        "data-[active]:border-primary data-[active]:bg-primary data-[active]:text-primary-foreground data-[active]:ring-2 data-[active]:ring-primary data-[active]:ring-offset-2",
        !isActive &&
          !isCompleted &&
          "border-border bg-muted text-muted-foreground",
        className
      )}
      {...props}
    >
      {isCompleted ? <CheckIcon className="size-4" /> : <span>{step}</span>}
    </span>
  )
}

// ─── StepperTitle ──────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-semibold leading-none", className)}
      {...props}
    />
  )
}

// ─── StepperDescription ────────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ──────────────────────────────────────────────────────────

type StepperSeparatorProps = {
  step: number
}

function StepperSeparator({
  step,
  className,
  ...props
}: React.ComponentProps<"div"> & StepperSeparatorProps) {
  const { activeStep } = useStepper()
  const isCompleted = activeStep > step

  return (
    <div
      data-slot="stepper-separator"
      data-completed={isCompleted ? true : undefined}
      className={cn(
        "shrink-0 bg-border transition-colors data-[completed]:bg-primary",
        "group-data-[orientation=horizontal]/stepper:mt-4 group-data-[orientation=horizontal]/stepper:h-0.5 group-data-[orientation=horizontal]/stepper:flex-1",
        "group-data-[orientation=vertical]/stepper:ml-[15px] group-data-[orientation=vertical]/stepper:h-4 group-data-[orientation=vertical]/stepper:w-0.5",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperPanel ──────────────────────────────────────────────────────────────

function StepperPanel({ className, ...props }: React.ComponentProps<"div">) {
  const { isActive } = useStepperItem()

  return (
    <div
      data-slot="stepper-panel"
      data-active={isActive ? true : undefined}
      className={cn(
        "mt-2",
        !isActive && "hidden",
        "group-data-[orientation=vertical]/stepper:ml-11",
        className
      )}
      {...props}
    />
  )
}

// ─── Exports ───────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
}
```

