"use client"

import * as React from "react"
import { Check } from "lucide-react"

import { cn } from "@/lib/utils"

// ---------------------------------------------------------------------------
// Root context
// ---------------------------------------------------------------------------

type StepperContextProps = {
  activeStep: number
  onStepChange: (step: number) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

// ---------------------------------------------------------------------------
// Item context
// ---------------------------------------------------------------------------

type StepperItemContextProps = {
  step: number
  isActive: boolean
  isCompleted: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextProps | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ---------------------------------------------------------------------------
// Stepper (root)
// ---------------------------------------------------------------------------

type StepperProps = {
  activeStep?: number
  defaultActiveStep?: number
  onStepChange?: (step: number) => void
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  activeStep: activeStepProp,
  defaultActiveStep = 1,
  onStepChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperProps) {
  const [activeStepState, setActiveStepState] =
    React.useState(defaultActiveStep)

  const activeStep =
    activeStepProp !== undefined ? activeStepProp : activeStepState

  const handleStepChange = React.useCallback(
    (step: number) => {
      if (activeStepProp === undefined) {
        setActiveStepState(step)
      }
      onStepChange?.(step)
    },
    [activeStepProp, onStepChange]
  )

  return (
    <StepperContext.Provider
      value={{ activeStep, onStepChange: handleStepChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex",
          "data-[orientation=horizontal]:flex-row",
          "data-[orientation=vertical]:flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperItem
// ---------------------------------------------------------------------------

type StepperItemProps = {
  step: number
}

function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperItemProps) {
  const { activeStep } = useStepper()
  const isActive = activeStep === step
  const isCompleted = activeStep > step

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted }}>
      <div
        data-slot="stepper-item"
        data-active={isActive || undefined}
        data-completed={isCompleted || undefined}
        className={cn(
          "group/stepper-item relative flex flex-col",
          "group-data-[orientation=horizontal]/stepper:items-center",
          "group-data-[orientation=vertical]/stepper:items-start",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperTrigger
// ---------------------------------------------------------------------------

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onStepChange } = useStepper()
  const { step } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      type="button"
      onClick={() => onStepChange(step)}
      className={cn(
        "inline-flex cursor-pointer items-center gap-2 rounded-md focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50",
        "group-data-[orientation=vertical]/stepper:items-start",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ---------------------------------------------------------------------------
// StepperIndicator
// ---------------------------------------------------------------------------

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"span">) {
  const { step, isActive, isCompleted } = useStepperItem()

  return (
    <span
      data-slot="stepper-indicator"
      data-active={isActive || undefined}
      data-completed={isCompleted || undefined}
      className={cn(
        "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-semibold transition-colors",
        "border-muted-foreground/30 text-muted-foreground",
        "data-[active]:border-primary data-[active]:bg-primary data-[active]:text-primary-foreground",
        "data-[completed]:border-primary data-[completed]:bg-primary data-[completed]:text-primary-foreground",
        className
      )}
      {...props}
    >
      {isCompleted ? <Check className="size-4" /> : (children ?? step)}
    </span>
  )
}

// ---------------------------------------------------------------------------
// StepperTitle
// ---------------------------------------------------------------------------

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-semibold", className)}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperDescription
// ---------------------------------------------------------------------------

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperSeparator — placed between <StepperItem> nodes at the root level
// ---------------------------------------------------------------------------

type StepperSeparatorProps = {
  step: number
}

function StepperSeparator({
  step,
  className,
  ...props
}: React.ComponentProps<"div"> & StepperSeparatorProps) {
  const { activeStep } = useStepper()
  const isCompleted = activeStep > step

  return (
    <div
      data-slot="stepper-separator"
      data-completed={isCompleted || undefined}
      className={cn(
        "shrink-0 bg-muted-foreground/30 transition-colors data-[completed]:bg-primary",
        "group-data-[orientation=horizontal]/stepper:mt-4 group-data-[orientation=horizontal]/stepper:h-0.5 group-data-[orientation=horizontal]/stepper:flex-1 group-data-[orientation=horizontal]/stepper:min-w-8",
        "group-data-[orientation=vertical]/stepper:ml-4 group-data-[orientation=vertical]/stepper:w-0.5 group-data-[orientation=vertical]/stepper:min-h-6 group-data-[orientation=vertical]/stepper:self-stretch",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperPanel — content panel placed inside a <StepperItem>
// ---------------------------------------------------------------------------

function StepperPanel({ className, ...props }: React.ComponentProps<"div">) {
  const { isActive } = useStepperItem()

  return (
    <div
      data-slot="stepper-panel"
      hidden={!isActive}
      className={cn(
        "group-data-[orientation=vertical]/stepper:ml-10",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
}

